"use client"

import { Canvas, useFrame } from "@react-three/fiber"
import { Stars } from "@react-three/drei"
import { useEffect, useMemo, useRef, useState } from "react"
import { generatePlanetByType, type PlanetOptions } from "../lib/utils"
import { Timer } from "three"

export interface PixelPlanetProps {
  type:
    | "ice"
    | "gas_giant_1"
    | "gas_giant_2"
    | "asteroid"
    | "star"
    | "lava"
    | "dry"
    | "earth"
    | "no_atmosphere"
  seed: number

  cameraZ?: number
  /**
   * advanced customization options for the planet.
   */
  advanced?: PlanetOptions
  className?: string
  stars?: boolean
  orbitControls?: boolean
  orbitControlsSensitivity?: number
}

const mapTypeToLabel: Record<PixelPlanetProps["type"], string> = {
  ice: "Ice Planet",
  gas_giant_1: "Gas giant 1",
  gas_giant_2: "Gas giant 2",
  asteroid: "Asteroid",
  star: "Star",
  lava: "Lava Planet",
  dry: "Dry Planet",
  earth: "Earth Planet",
  no_atmosphere: "No atmosphere",
}

function CameraUpdater({ cameraZ }: { cameraZ: number }) {
  useFrame(({ camera }) => {
    if (camera.position.z !== cameraZ) {
      camera.position.set(0, 0, cameraZ)
      camera.lookAt(0, 0, 0)
    }
  })
  return null
}

function PlanetContent({
  type,
  seed,
  advanced: options,
  rotationOffset = 0,
}: PixelPlanetProps & { rotationOffset?: number }) {
  const planetLabel = mapTypeToLabel[type]

  // Generate planet group when type changes
  const planet = useMemo(() => {
    return generatePlanetByType(planetLabel, options)
  }, [planetLabel, options])

  // Update seed when it changes
  useEffect(() => {
    if (!planet) return
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    planet.children.forEach((layer: any) => {
      if (layer.material && layer.material.uniforms) {
        if (layer.material.uniforms["seed"]) {
          layer.material.uniforms["seed"].value = seed
        }
      }
    })
  }, [planet, seed])

  const timer = useMemo(() => new Timer(), [])

  // Animation loop - update time and manual offset for texture scrolling
  useFrame(() => {
    if (!planet) return

    timer.update()

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    planet.children.forEach((layer: any) => {
      if (layer.material && layer.material.uniforms) {
        if (layer.material.uniforms["time"]) {
          layer.material.uniforms["time"].value =
            timer.getElapsed() + rotationOffset
        }
      }
    })
  })

  if (!planet) return null

  return <primitive object={planet} />
}

export function PixelPlanet({
  className,
  stars,
  orbitControls,
  orbitControlsSensitivity,
  ...props
}: PixelPlanetProps & React.ComponentProps<typeof Canvas>) {
  const [isDragging, setIsDragging] = useState(false)
  const [rotationOffset, setRotationOffset] = useState(0)
  const [velocity, setVelocity] = useState(0)
  const dragStartXRef = useRef<number>(0)
  const rotationAtDragStartRef = useRef<number>(0)
  const lastDragTimeRef = useRef<number>(0)
  const lastDragXRef = useRef<number>(0)

  const orbitControlsEnabled =
    orbitControls ?? orbitControlsSensitivity !== undefined
  const sensitivity = orbitControlsSensitivity ?? -0.005 // Default sensitivity
  const friction = 0.95 // Friction coefficient (lower = more friction)

  const defaultCameraZ = props.type === "gas_giant_2" ? 1.5 : 1.0
  const cameraZ =
    props.cameraZ ?? props.advanced?.cameraDistance ?? defaultCameraZ

  // Apply velocity and friction when not dragging
  useEffect(() => {
    if (isDragging || !orbitControlsEnabled) return

    let animationFrame: number

    const applyMomentum = () => {
      setVelocity(v => {
        const newVelocity = v * friction
        // Stop when velocity is very small
        if (Math.abs(newVelocity) < 0.0001) {
          return 0
        }
        return newVelocity
      })

      setRotationOffset(offset => offset + velocity)

      // Continue animation loop if there's still velocity
      if (Math.abs(velocity) > 0.0001) {
        animationFrame = requestAnimationFrame(applyMomentum)
      }
    }

    if (Math.abs(velocity) > 0.0001) {
      animationFrame = requestAnimationFrame(applyMomentum)
    }

    return () => {
      if (animationFrame) {
        cancelAnimationFrame(animationFrame)
      }
    }
  }, [isDragging, velocity, orbitControlsEnabled, friction])

  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!orbitControlsEnabled) return
    setIsDragging(true)
    setVelocity(0) // Stop any existing momentum
    dragStartXRef.current = e.clientX
    lastDragXRef.current = e.clientX
    lastDragTimeRef.current = Date.now()
    rotationAtDragStartRef.current = rotationOffset
    ;(e.target as HTMLElement).setPointerCapture(e.pointerId)
  }

  const handlePointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!orbitControlsEnabled || !isDragging) return

    const currentTime = Date.now()
    const deltaX = e.clientX - dragStartXRef.current
    const deltaTime = currentTime - lastDragTimeRef.current

    // Update rotation
    const newOffset = rotationAtDragStartRef.current + deltaX * sensitivity
    setRotationOffset(newOffset)

    // Calculate velocity based on movement since last frame
    if (deltaTime > 0) {
      const movementDelta = e.clientX - lastDragXRef.current
      const instantVelocity =
        ((movementDelta * sensitivity) / Math.max(deltaTime, 16)) * 16
      setVelocity(instantVelocity)
    }

    lastDragXRef.current = e.clientX
    lastDragTimeRef.current = currentTime
  }

  const handlePointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!orbitControlsEnabled) return
    setIsDragging(false)
    ;(e.target as HTMLElement).releasePointerCapture(e.pointerId)
    // Velocity is already set from last move event, momentum will take over
  }

  const cursorStyle = orbitControlsEnabled
    ? isDragging
      ? "grabbing"
      : "grab"
    : "inherit"

  const canvasRef = useRef<HTMLDivElement>(null)

  // Apply cursor style directly to ensure it overrides any CSS
  useEffect(() => {
    if (canvasRef.current) {
      const canvas = canvasRef.current.querySelector("canvas")
      if (canvas && orbitControlsEnabled) {
        canvas.style.cursor = cursorStyle
      }
    }
  }, [cursorStyle, orbitControlsEnabled])

  return (
    <div
      ref={canvasRef}
      className={className}
      style={{
        ...props.style,
        touchAction: "none",
        userSelect: "none",
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerLeave={handlePointerUp}
    >
      <Canvas
        camera={{ position: [0, 0, cameraZ] }}
        style={{
          cursor: cursorStyle,
          touchAction: "none",
        }}
        {...props}
      >
        <ambientLight intensity={0.5} />
        <pointLight position={[10, 10, 10]} intensity={1} />

        {stars && (
          <Stars
            radius={300}
            depth={50}
            count={5000}
            factor={4}
            saturation={0}
            fade
            speed={1}
          />
        )}

        <PlanetContent {...props} rotationOffset={rotationOffset} />

        <CameraUpdater cameraZ={cameraZ} />

        {/* <OrbitControls enablePan={false} /> */}
      </Canvas>
    </div>
  )
}

import { createAsteroid } from "./Planets/asteroid"
import { createDryPlanet } from "./Planets/dryPlanet"
import { createEarthPlanet } from "./Planets/earthPlanet"
import { createGasGiant } from "./Planets/gasGiant"
import { createGasGiantRing } from "./Planets/gasGiantRing"
import { createIcePlanet } from "./Planets/icePlanet"
import { createLavaPlanet } from "./Planets/lavaPlanet"
import { createNoAtmospherePlanet } from "./Planets/noAtmospherePlanet"
import { createStarPlanet } from "./Planets/starPlanet"
import { Group } from "three"

export function rand(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1) + min)
}

export function flip(): boolean {
  return Math.random() > 0.5
}

export function randomPointOnSphere(): { x: number; y: number; z: number } {
  const u = Math.random()
  const v = Math.random()
  const theta = 2 * Math.PI * u
  const phi = Math.acos(2 * v - 1)
  const x = 0 + 1 * Math.sin(phi) * Math.cos(theta)
  const y = 0 + 1 * Math.sin(phi) * Math.sin(theta)
  const z = 0 + 1 * Math.cos(phi)
  return { x: x, y: y, z: z }
}

export interface PlanetOptions {
  lightPosition?: [number, number]
  rotation?: number
  rotationSpeed?: number
  pixelSize?: number
  waterLevel?: number // for lakes/rivers
  cloudCover?: number
  cameraDistance?: number // for manual zoom control
  orbitControls?: boolean // Enable drag-to-rotate interaction
  orbitControlsSensitivity?: number // Custom sensitivity for drag-to-rotate
  colors?: {
    base?: [number, number, number, number][]
    craters?: [number, number, number, number][]
    rivers?: [number, number, number, number][]
    clouds?: [number, number, number, number][]
  }
}

export function generatePlanetByType(
  type: string,
  options?: PlanetOptions,
): Group | undefined {
  switch (type) {
    case "No atmosphere":
      return createNoAtmospherePlanet(options)
    case "Ice Planet":
      return createIcePlanet(options)
    case "Gas giant 1":
      return createGasGiant(options)
    case "Gas giant 2":
      return createGasGiantRing(options)
    case "Asteroid":
      return createAsteroid(options)
    case "Star":
      return createStarPlanet(options)
    case "Lava Planet":
      return createLavaPlanet(options)
    case "Dry Planet":
      return createDryPlanet(options)
    case "Earth Planet":
      return createEarthPlanet(options)
  }
}

export function getSeedFromId(id: string): number {
  let hash = 0
  for (let i = 0; i < id.length; i++) {
    const char = id.charCodeAt(i)
    hash = (hash << 5) - hash + char
    hash = hash & hash
  }

  // Generate a 5-digit seed (range: 10000 to 99999)
  // 5 digits provides 100k unique variations while staying within
  // GLSL float precision limits (32-bit floats have ~7 decimal digits of precision)
  const min5Digit = 10000
  const max5Digit = 99999
  const range = max5Digit - min5Digit + 1

  return min5Digit + (Math.abs(hash) % range)
}

import { Clock, Group, Scene, WebGLRenderer } from "three"

export function createScene(): Scene {
  return new Scene()
}

export function createClock(): Clock {
  return new Clock()
}

export function createWebGlRenderer(): WebGLRenderer {
  return new WebGLRenderer()
}

export function createGroup(): Group {
  return new Group()
}

import { PerspectiveCamera } from "three"

export const createCamera = (
  fov: number,
  aspect: number,
  near: number,
  far: number,
): PerspectiveCamera => {
  return new PerspectiveCamera(fov, aspect, near, far)
}

import {
  Group,
  Mesh,
  PlaneGeometry,
  ShaderMaterial,
  Vector2,
  Vector4,
} from "three"
import { flip } from "../utils"

const vertexShader = (): string => {
  return `
    varying vec3 vUv; 

    void main() {
      vUv = position; 

      vec4 modelViewPosition = modelViewMatrix * vec4(position, 1.0);
      gl_Position = projectionMatrix * modelViewPosition; 
    }
  `
}

const fragmentShaderPlanet = (): string => {
  return `
        varying vec3 vUv;
        uniform float pixels;
        uniform float rotation;
        uniform vec2 light_origin;
        uniform vec4 color1;
        uniform vec4 color2;
        uniform vec4 color3;
        uniform float size;
        int OCTAVES = 4;
        uniform float seed;
        uniform float time;
        bool should_dither = true;

        float rand(vec2 coord) {
            return fract(sin(dot(coord.xy ,vec2(12.9898,78.233))) * 15.5453 * seed);
        }

        float noise(vec2 coord){
            vec2 i = floor(coord);
            vec2 f = fract(coord);

            float a = rand(i);
            float b = rand(i + vec2(1.0, 0.0));
            float c = rand(i + vec2(0.0, 1.0));
            float d = rand(i + vec2(1.0, 1.0));

            vec2 cubic = f * f * (3.0 - 2.0 * f);

            return mix(a, b, cubic.x) + (c - a) * cubic.y * (1.0 - cubic.x) + (d - b) * cubic.x * cubic.y;
        }

        float fbm(vec2 coord){
            float value = 0.0;
            float scale = 0.5;

            for(int i = 0; i < OCTAVES ; i++){
                value += noise(coord) * scale;
                coord *= 2.0;
                scale *= 0.5;
            }
            return value;
        }

        bool dither(vec2 uv1, vec2 uv2) {
            return mod(uv1.x+uv2.y,2.0/pixels) <= 1.0 / pixels;
        }

        vec2 rotate(vec2 coord, float angle){
            coord -= 0.5;
            coord *= mat2(vec2(cos(angle),-sin(angle)),vec2(sin(angle),cos(angle)));
            return coord + 0.5;
        }

        // by Leukbaars from https://www.shadertoy.com/view/4tK3zR
        float circleNoise(vec2 uv) {
            float uv_y = floor(uv.y);
            uv.x += uv_y*.31;
            vec2 f = fract(uv);
            float h = rand(vec2(floor(uv.x),floor(uv_y)));
            float m = (length(f-0.25-(h*0.5)));
            float r = h*0.25;
            return m = smoothstep(r-.10*r,r,m);
        }

        float crater(vec2 uv) {
            float c = 1.0;
            for (int i = 0; i < 2; i++) {
                c *= circleNoise((uv * size) + (float(i+1)+10.));
            }
            return 1.0 - c;
        }

        void main() {
            vec2 uv = (floor(vUv.xy*pixels)/pixels) + 0.5;

            // we use this val later to interpolate between shades
            bool dith = dither(uv, vUv.xy);

            // distance from center
            float d = distance(uv, vec2(0.5));

            // optional rotation, do this after the dither or the dither will look very messed up
            uv = rotate(uv, time*0.1);

            // two noise values with one slightly offset according to light source, to create shadows later
            float n = fbm(uv * size);
            float n2 = fbm(uv * size + (rotate(light_origin, rotation)-0.5) * 0.5);

            // step noise values to determine where the edge of the asteroid is
            // step cutoff value depends on distance from center
            float n_step = step(0.2, n - d);
            float n2_step = step(0.2, n2 - d);

            // with this val we can determine where the shadows should be
            float noise_rel = (n2_step + n2) - (n_step + n);

            // two crater values, again one extra for the shadows
            float c1 = crater(uv );
            float c2 = crater(uv + (light_origin-0.5)*0.03);

            // now we just assign colors depending on noise values and crater values
            // base
            vec4 col = color2;

            // noise
            if (noise_rel < -0.06 || (noise_rel < -0.04 && (dith || !should_dither))) {
                col = color1;
            }
            if (noise_rel > 0.05 || (noise_rel > 0.03 && (dith || !should_dither))) {
                col = color3;
            }

            // crater
            if (c1 > 0.4)  {
                col = color2;
            }
            if (c2<c1) {
                col = color3;
            }

            gl_FragColor = vec4(col.rgb, n_step * col.a);
            if (gl_FragColor.a < 0.01) discard;
        }
    `
}

import { type PlanetOptions } from "../utils"

export const createAsteroid = (options?: PlanetOptions): Group => {
  const lightPos = options?.lightPosition
    ? new Vector2(options.lightPosition[0], options.lightPosition[1])
    : new Vector2(0.39, 0.7)
  const colors = options?.colors?.base
    ? options.colors.base.map(c => new Vector4(c[0], c[1], c[2], c[3]))
    : null
  const rotation = options?.rotation ?? 0.0

  const colorPalette = colors
    ? colors
    : [
        new Vector4(155 / 255, 158 / 255, 184 / 255, 1),
        new Vector4(71 / 255, 97 / 255, 124 / 255, 1),
        new Vector4(53 / 255, 57 / 255, 85 / 255, 1),
      ]
  const planetGeometry = new PlaneGeometry(1.5, 1.5)
  const planetMaterial = new ShaderMaterial({
    uniforms: {
      pixels: { value: 100.0 },
      color1: { value: colorPalette[0] },
      size: { value: Math.random() * 10 },
      color2: { value: colorPalette[1] },
      color3: { value: colorPalette[2] },
      light_origin: { value: lightPos },
      rotation: { value: rotation },
      seed: { value: flip() ? Math.random() * 10 : Math.random() * 100 },
      time: { value: 0.0 },
    },
    vertexShader: vertexShader(),
    fragmentShader: fragmentShaderPlanet(),
    transparent: true,
  })

  const asteroid = new Mesh(planetGeometry, planetMaterial)

  return new Group().add(asteroid)
}

import {
  Group,
  Mesh,
  NearestFilter,
  PlaneGeometry,
  ShaderMaterial,
  TextureLoader,
  Vector2,
} from "three"
import { flip } from "../utils"

const vertexShader = (): string => {
  return `
    varying vec3 vUv; 

    void main() {
      vUv = position; 

      vec4 modelViewPosition = modelViewMatrix * vec4(position, 1.0);
      gl_Position = projectionMatrix * modelViewPosition; 
    }
  `
}

const fragmentShader = (): string => {
  return `
        varying vec3 vUv;
        uniform float pixels;
        uniform float rotation;
        uniform vec2 light_origin;
        float light_distance1 = 0.362;
        float light_distance2 = 0.525;
        uniform float time_speed;
        uniform sampler2D colors;
        float size = 10.0;
        int OCTAVES = 4;
        uniform float seed;
        uniform float time;
        bool should_dither = true;

        float rand(vec2 coord) {
            coord = mod(coord, vec2(1.0,1.0)*floor(size+0.5));
            return fract(sin(dot(coord.xy ,vec2(12.9898,78.233))) * 15.5453 * seed);
        }

        float noise(vec2 coord){
            vec2 i = floor(coord);
            vec2 f = fract(coord);

            float a = rand(i);
            float b = rand(i + vec2(1.0, 0.0));
            float c = rand(i + vec2(0.0, 1.0));
            float d = rand(i + vec2(1.0, 1.0));

            vec2 cubic = f * f * (3.0 - 2.0 * f);

            return mix(a, b, cubic.x) + (c - a) * cubic.y * (1.0 - cubic.x) + (d - b) * cubic.x * cubic.y;
        }

        float fbm(vec2 coord){
            float value = 0.0;
            float scale = 0.5;

            for(int i = 0; i < OCTAVES ; i++){
                value += noise(coord) * scale;
                coord *= 2.0;
                scale *= 0.5;
            }
            return value;
        }

        bool dither(vec2 uv1, vec2 uv2) {
            return mod(uv1.x+uv2.y,2.0/pixels) <= 1.0 / pixels;
        }

        vec2 rotate(vec2 coord, float angle){
            coord -= 0.5;
            coord *= mat2(vec2(cos(angle),-sin(angle)),vec2(sin(angle),cos(angle)));
            return coord + 0.5;
        }

        vec2 spherify(vec2 uv) {
            vec2 centered= uv *2.0-1.0;
            float z = sqrt(1.0 - dot(centered.xy, centered.xy));
            vec2 sphere = centered/(z + 1.0);
            return sphere * 0.5+0.5;
        }


        void main() {
            //pixelize uv
            vec2 uv = (floor(vUv.xy*pixels)/pixels) + 0.5;
            bool dith = dither(uv, vUv.xy);

            // cut out a circle
            float d_circle = distance(uv, vec2(0.5));
            float a = step(d_circle, 0.49999);

            uv = spherify(uv);

            // check distance distance to light
            float d_light = distance(uv , vec2(light_origin));

            uv = rotate(uv, rotation);

            // noise
            float f = fbm(uv*size+vec2(time*time_speed, 0.0));

            // remap light
            d_light = smoothstep(-0.3, 1.2, d_light);

            if (d_light < light_distance1) {
                d_light *= 0.9;
            }
            if (d_light < light_distance2) {
                d_light *= 0.9;
            }


            float c = d_light*pow(f,0.8)*3.5; // change the magic nums here for different light strengths

            // apply dithering
            if (dith || !should_dither) {
                c += 0.02;
                c *= 1.05;
            }

            // now we can assign colors based on distance to light origin
            float posterize = floor(c*4.0)/4.0;
            vec4 col = texture(colors, vec2(posterize, 0.0));

            gl_FragColor = vec4(col.rgb, a * col.a);

        }
    `
}

import { type PlanetOptions } from "../utils"

export function createDryPlanet(options?: PlanetOptions): Group {
  const {
    lightPosition,
    colors,
    rotationSpeed = 0.1,
    rotation = 0.0,
  } = options ?? {}

  const lightPos = lightPosition
    ? new Vector2(lightPosition[0], lightPosition[1])
    : new Vector2(0.39, 0.7)

  const colorSchemeTexture = new TextureLoader().load(
    typeof colors === "string"
      ? colors
      : "/pixel-planet/colorScheme/colorScheme2.png",
  )
  colorSchemeTexture.magFilter = NearestFilter
  colorSchemeTexture.minFilter = NearestFilter

  const planetGeometry = new PlaneGeometry(1, 1)
  const planetMaterial = new ShaderMaterial({
    uniforms: {
      pixels: { value: 100.0 },
      colors: { value: colorSchemeTexture },
      light_origin: { value: lightPos },
      time_speed: { value: rotationSpeed },
      rotation: { value: rotation },
      seed: { value: flip() ? Math.random() * 10 : Math.random() * 100 },
      time: { value: 0.0 },
    },
    vertexShader: vertexShader(),
    fragmentShader: fragmentShader(),
    transparent: true,
  })

  const basePlanet = new Mesh(planetGeometry, planetMaterial)
  return new Group().add(basePlanet)
}

import { Mesh, PlaneGeometry, ShaderMaterial, Vector4 } from "three"

const vertexShader = (): string => {
  return `
    varying vec3 vUv; 

    void main() {
      vUv = position; 

      vec4 modelViewPosition = modelViewMatrix * vec4(position, 1.0);
      gl_Position = projectionMatrix * modelViewPosition; 
    }
  `
}

const fragmentShader = (): string => {
  return `
        varying vec3 vUv;
        uniform vec4 color;
        uniform vec4 color2;
        uniform vec4 color3;
        float pixels = 100.0;

        float dist(vec2 p0, vec2 pf){
            return sqrt((pf.x-p0.x)*(pf.x-p0.x)+(pf.y-p0.y)*(pf.y-p0.y));
        }

        void main() {
            vec2 uv = (floor(vUv.xy*pixels)/pixels) + 0.5;   
            vec2 pos_ndc = 2.0 * uv.xy  - 1.0;
            float dist = length(pos_ndc);

            float step0 = 0.65;
            float step1 = 0.87;
            float step2 = 0.97;
            float step3 = 1.04;
            float step4 = 1.04;

            vec4 color = mix(vec4(0,0,0,0), color, smoothstep(step0, step1, dist));
            color = mix(color, color2, smoothstep(step1, step2, dist));
            color = mix(color, color3, smoothstep(step2, step3, dist));
            color = mix(color, vec4(0,0,0,0), smoothstep(step3, step4, dist));

            gl_FragColor = color;
            if (gl_FragColor.a < 0.01) discard;
        }
    `
}

export const createAtmosphereLayer = (): Mesh => {
  const atmopshereGeometry = new PlaneGeometry(1.02, 1.02)
  const atmopshereMaterial = new ShaderMaterial({
    uniforms: {
      color: { value: new Vector4(173 / 255, 216 / 255, 230 / 255, 0.25) },
      color2: { value: new Vector4(0 / 255, 127 / 255, 255 / 255, 0.35) },
      color3: { value: new Vector4(0 / 255, 0 / 255, 128 / 255, 0.45) },
    },
    vertexShader: vertexShader(),
    fragmentShader: fragmentShader(),
    transparent: true,
  })

  const atmosphereLayer = new Mesh(atmopshereGeometry, atmopshereMaterial)

  return atmosphereLayer
}

import {
  Mesh,
  NearestFilter,
  PlaneGeometry,
  ShaderMaterial,
  TextureLoader,
} from "three"
import { flip } from "../utils"

const fragmentShaderDust = (): string => {
  return `
    varying vec3 vUv;
    float size = 10.0;
    int OCTAVES = 12;
    uniform float seed;
    float pixels = 100.0;
    bool should_tile = false;
    bool reduce_background = false;
    uniform sampler2D colorscheme;
    vec2 uv_correct = vec2(1.0);


    float rand(vec2 coord, float tilesize) {
        if (should_tile) {
            coord = mod(coord / uv_correct, tilesize );
        }

        return fract(sin(dot(coord.xy ,vec2(12.9898,78.233))) * (15.5453 + seed));
    }

    float noise(vec2 coord, float tilesize){
        vec2 i = floor(coord);
        vec2 f = fract(coord);

        float a = rand(i, tilesize);
        float b = rand(i + vec2(1.0, 0.0), tilesize);
        float c = rand(i + vec2(0.0, 1.0), tilesize);
        float d = rand(i + vec2(1.0, 1.0), tilesize);

        vec2 cubic = f * f * (3.0 - 2.0 * f);

        return mix(a, b, cubic.x) + (c - a) * cubic.y * (1.0 - cubic.x) + (d - b) * cubic.x * cubic.y;
    }

    float fbm(vec2 coord, float tilesize){
        float value = 0.0;
        float scale = 0.5;

        for(int i = 0; i < OCTAVES ; i++){
            value += noise(coord, tilesize ) * scale;
            coord *= 2.0;
            scale *= 0.5;
        }
        return value;
    }

    bool dither(vec2 uv1, vec2 uv2) {
        return mod(uv1.y+uv2.x,2.0/pixels) <= 1.0 / pixels;
    }

    float circleNoise(vec2 uv, float tilesize) {
        if (should_tile) {
            uv = mod(uv, tilesize);
        }

        float uv_y = floor(uv.y);
        uv.x += uv_y*.31;
        vec2 f = fract(uv);
        float h = rand(vec2(floor(uv.x),floor(uv_y)), tilesize);
        float m = (length(f-0.25-(h*0.5)));
        float r = h*0.25;
        return smoothstep(0.0, r, m*0.75);
    }

    float cloud_alpha(vec2 uv, float tilesize) {
        float c_noise = 0.0;

        // more iterations for more turbulence
        int iters = 2;
        for (int i = 0; i < iters; i++) {
            c_noise += circleNoise(uv * 0.5 + (float(i+1)) + vec2(-0.3, 0.0), ceil(tilesize * 0.5));
        }
        float fbm = fbm(uv+c_noise, tilesize);

        return fbm;
    }

    void main() {
        // pixelizing and dithering
        vec2 uv = floor((vUv.xy) * pixels) / pixels * uv_correct;
        bool dith = dither(uv, vUv.xy);

        // noise for the dust
        // the + vec2(x,y) is to create an offset in noise values
        float n_alpha = fbm(uv * ceil(size * 0.5) +vec2(2,2), ceil(size * 0.5));
        float n_dust = cloud_alpha(uv * size, size);
        float n_dust2 = fbm(uv * ceil(size * 0.2)  -vec2(2,2),ceil(size * 0.2));
        float n_dust_lerp = n_dust2 * n_dust;

        // apply dithering
        if (dith) {
            n_dust_lerp *= 0.95;
        }

        // choose alpha value
        float a_dust = step(n_alpha , n_dust_lerp * 1.8);
        n_dust_lerp = pow(n_dust_lerp, 3.2) * 56.0;
        if (dith) {
            n_dust_lerp *= 1.1;
        }

        // choose & apply colors
        if (reduce_background) {
            n_dust_lerp = pow(n_dust_lerp, 0.8) * 0.7;
        }

        float col_value = floor(n_dust_lerp) / 7.0;
        vec3 col = texture(colorscheme, vec2(col_value, 0.0)).rgb;


        gl_FragColor = vec4(col, a_dust);

    }
    `
}

const fragmentShaderNebula = (): string => {
  return `
        varying vec3 vUv;
        float size = 5.0;
        int OCTAVES = 8;
        uniform float seed;
        float pixels = 100.0;
        uniform sampler2D colorscheme;
        vec4 background_color = vec4(0,0,0,0);
        bool should_tile = false;
        bool reduce_background = false;
        vec2 uv_correct = vec2(1.0);

        float rand(vec2 coord, float tilesize) {
            if (should_tile) {
                coord = mod(coord / uv_correct, tilesize);
            }

            return fract(sin(dot(coord.xy ,vec2(12.9898,78.233))) * (15.5453 + seed));
        }

        float noise(vec2 coord, float tilesize){
            vec2 i = floor(coord);
            vec2 f = fract(coord);

            float a = rand(i, tilesize);
            float b = rand(i + vec2(1.0, 0.0), tilesize);
            float c = rand(i + vec2(0.0, 1.0), tilesize);
            float d = rand(i + vec2(1.0, 1.0), tilesize);

            vec2 cubic = f * f * (3.0 - 2.0 * f);

            return mix(a, b, cubic.x) + (c - a) * cubic.y * (1.0 - cubic.x) + (d - b) * cubic.x * cubic.y;
        }

        float fbm(vec2 coord, float tilesize){
            float value = 0.0;
            float scale = 0.5;

            for(int i = 0; i < OCTAVES ; i++){
                value += noise(coord, tilesize ) * scale;
                coord *= 2.0;
                scale *= 0.5;
            }
            return value;
        }

        bool dither(vec2 uv1, vec2 uv2) {
            return mod(uv1.y+uv2.x,2.0/pixels) <= 1.0 / pixels;
        }

        float circleNoise(vec2 uv, float tilesize) {
            if (should_tile) {
                uv = mod(uv, tilesize / uv_correct);
            }

            float uv_y = floor(uv.y);
            uv.x += uv_y*.31;
            vec2 f = fract(uv);
            float h = rand(vec2(floor(uv.x),floor(uv_y)), tilesize);
            float m = (length(f-0.25-(h*0.5)));
            float r = h*0.25;
            return smoothstep(0.0, r, m*0.75);
        }

        float cloud_alpha(vec2 uv, float tilesize) {
            float c_noise = 0.0;

            // more iterations for more turbulence
            int iters = 4;
            for (int i = 0; i < iters; i++) {
                c_noise += circleNoise(uv * 0.5 + (float(i+1)) + vec2(-0.3, 0.0), ceil(tilesize * 0.5));
            }
            float fbm = fbm(uv+c_noise, tilesize);

            return fbm;
        }

        void main() {
            // pixelizing and dithering
            vec2 uv = (floor(vUv.xy*pixels)/pixels) + 0.5; 

            // distance from center
            float d =  distance(uv, vec2(0.5)) * 0.4;

            uv *= uv_correct;
            bool dith = dither(uv, vUv.xy);

            // noise for the inside of the nebulae
            float n = cloud_alpha(uv * size, size);
            float n2 = fbm(uv * size + vec2(1, 1), size);
            float n_lerp = n2 * n;
            float n_dust = cloud_alpha(uv * size, size);
            float n_dust_lerp = n_dust * n_lerp;

            // apply dithering
            if (dith) {
                n_dust_lerp *= 0.95;
                n_lerp *= 0.95;
                d*= 0.98;
            }

            // slightly offset alpha values to create thin bands around the nebulae
            float a = step(n2, 0.1 + d);
            float a2 = step(n2, 0.115 + d);
            if (should_tile) {
                a = step(n2, 0.3);
                a2 = step(n2, 0.315);
            }

            // choose colors
            if (reduce_background) {
                n_dust_lerp = pow(n_dust_lerp, 1.2) * 0.7;
            }
            float col_value = 0.0;
            if (a2 > a) {
                col_value = floor(n_dust_lerp * 35.0) / 7.0;
            } else {
                col_value = floor(n_dust_lerp * 14.0) / 7.0;
            }

            // apply colors
            vec3 col = texture(colorscheme, vec2(col_value, 0.0)).rgb;
            if (col_value < 0.1) {
                col = background_color.rgb;
            }
            gl_FragColor = vec4(col, a2);

        }
    `
}

